return {
    "MeanderingProgrammer/render-markdown.nvim",
    ft = { "markdown" },
    dependencies = { "nvim-treesitter/nvim-treesitter", "nvim-mini/mini.nvim" }, -- if you use the mini.nvim suite
    -- dependencies = { 'nvim-treesitter/nvim-treesitter', 'nvim-mini/mini.icons' },        -- if you use standalone mini plugins
    -- dependencies = { 'nvim-treesitter/nvim-treesitter', 'nvim-tree/nvim-web-devicons' }, -- if you prefer nvim-web-devicons
    -- TODO: Setup special links with brackets [[issue] sdfsdf](link) https://github.com/MeanderingProgrammer/render-markdown.nvim#links
    ---@module 'render-markdown'
    ---@type render.md.UserConfig
    opts = {
        render_modes = { "n", "c", "t", "i", "v" },
        completions = { lsp = { enabled = true } },
        debounce = 250,
        bullet = {
            icons = " ",
        },
        -- win_options = {
        --     conceallevel = {
        --         default = vim.o.conceallevel,
        --         rendered = 0,
        --     },
        -- },
        checkbox = {
            unchecked = {
                icon = "󰄰 ",
            },
            checked = {
                icon = "󰗠 ",
                -- highlight = "RenderMarkdownSuccess",
                highlight = "@markup.list.checked",
            },
            custom = {
                progress = {
                    raw = "[~]",
                    rendered = "󰦕 ",
                    highlight = "@markup.list.unchecked",
                },
                event = {
                    raw = "[o]",
                    rendered = "󰃭 ",
                    highlight = "RenderMarkdownInfo",
                },
                migrated = {
                    raw = "[>]",
                    rendered = "󰁖 ",
                    highlight = "RenderMarkdownWarn",
                },
                scheduled = {
                    raw = "[<]",
                    rendered = "󰸗 ",
                    highlight = "RenderMarkdownInfo",
                },
            },
        },
    },
}

  (section)
] @fold)

(section
  (list) @fold)
]])
        end,
    },

    {
        "MeanderingProgrammer/treesitter-modules.nvim",
        lazy = false,
        dependencies = { "nvim-treesitter/nvim-treesitter" },
        opts = {
            auto_install = true,
            ensure_installed = {
                "bash",
                "c",
                "css",
                "go",
                "html",
                "javascript",
                "json",
                "lua",
                "markdown",
                "markdown_inline",
                "rust",
                "toml",
                "astro",
                "typescript",
                "vim",
                "vimdoc",
                "yaml",
                "http",
            },
            highlight = {
                enable = true,
                additional_vim_regex_highlighting = false,
            },
            indent = {
                enable = false,
            },
            incremental_selection = {
                enable = true,
                disable = { "vim", "qf" },
                keymaps = {
                    init_selection = "vv",
                    node_incremental = "v",
                    node_decremental = "<BS>",
                },
            },
        },
    },

    -- Only needed for its query files (.scm) - MiniAi uses these
    {
        "nvim-treesitter/nvim-treesitter-textobjects",
        branch = "main",
        lazy = false,
    },

    {
        "tpope/vim-sleuth",
        event = "BufRead",
    },

    {
        "windwp/nvim-ts-autotag",
        event = "InsertEnter",
        opts = {},
    },

    {
        "folke/ts-comments.nvim",
        opts = {},
        event = "VeryLazy",
    },

    {
        "aaronik/treewalker.nvim",
        event = "VeryLazy",

        -- The following options are the defaults.
        -- Treewalker aims for sane defaults, so these are each individually optional,
        -- and setup() does not need to be called, so the whole opts block is optional as well.
        opts = {
            -- Whether to briefly highlight the node after jumping to it
            highlight = true,

            -- How long should above highlight last (in ms)
            highlight_duration = 250,

            -- The color of the above highlight. Must be a valid vim highlight group.
            -- (see :h highlight-group for options)
            highlight_group = "CursorLine",

            -- Whether the plugin adds movements to the jumplist -- true | false | 'left'
            --  true: All movements more than 1 line are added to the jumplist. This is the default,
            --        and is meant to cover most use cases. It's modeled on how { and } natively add
            --        to the jumplist.
            --  false: Treewalker does not add to the jumplist at all
            --  "left": Treewalker only adds :Treewalker Left to the jumplist. This is usually the most
            --          likely one to be confusing, so it has its own mode.
            jumplist = true,
        },
        keys = {
            { mode = { "n", "v" }, "<Up>", "<CMD>Treewalker Up<CR>" },
            { mode = { "n", "v" }, "<Down>", "<CMD>Treewalker Down<CR>" },
            { mode = { "n", "v" }, "<Left>", "<CMD>Treewalker Left<CR>" },
            { mode = { "n", "v" }, "<Right>", "<CMD>Treewalker Right<CR>" },

            { mode = { "n", "v" }, "<S-Up>", "<CMD>Treewalker SwapUp<CR>" },
            { mode = { "n", "v" }, "<S-Down>", "<CMD>Treewalker SwapDown<CR>" },
            { mode = { "n", "v" }, "<S-Left>", "<CMD>Treewalker SwapLeft<CR>" },
            { mode = { "n", "v" }, "<S-Right>", "<CMD>Treewalker SwapRight<CR>" },
        },
    },
}

return M.specs
